int ldr = A0;
int buzzer = 9;
int led = 8;
int threshold = 500;

void setup() {
  pinMode(buzzer, OUTPUT);
  pinMode(led, OUTPUT);
  Serial.begin(9600);
}

void loop() {
  int value = analogRead(ldr);

  if (value > threshold) {
    digitalWrite(led, HIGH);
    tone(buzzer, 1000);
  } else {
    digitalWrite(led, LOW);
    noTone(buzzer);
  }
  delay(100);
}
